const item = $input.item.json;
const rawId = item.record_id;

// 1. Determine if we actually have an ID (ignore null, undefined, or empty strings)
const hasId = rawId && String(rawId).trim() !== "" && rawId !== 0;

// 2. Determine the correct Key Name based on the module
let dynamicKey = "recordId"; 
if (item.module === 'Leads') dynamicKey = "leadId";
else if (item.module === 'Contacts') dynamicKey = "contactId";
else if (item.module === 'Accounts') dynamicKey = "accountId";
else if (item.module === 'Deals') dynamicKey = "dealId";

// 3. Build the output
const output = { ...item };

if (hasId) {
  const stringId = String(rawId);
  output.record_id = stringId; // Keep the original key as string
  output[dynamicKey] = stringId; // Add the module-specific key (e.g., leadId)
  output.is_new_record = false;
} else {
  // Ensure we don't pass an empty ID string that might confuse the API
  delete output.record_id;
  output.is_new_record = true;
}

return output;
